#include <stdio.h>
#include <stdbool.h>

int main() {
    int n, k;
    scanf("%d%d", &n, &k);

    char s[n + 1];
    scanf("%s", s);

    int cnt = 0;
    bool maxN = true, res = false;
    for(int i = 0; i < n; ++i) {
        cnt = (s[i] == 'N' ? cnt + 1 : 0);
        maxN &= cnt <= k;
    }

    if (maxN) {
        for (int i = 0; i + k <= n; ++i) {
            bool f = true;
            for (int j = i; j < i + k; ++j)
                f &= s[j] != 'Y';

            if (i != 0)
                f &= s[i - 1] != 'N';
            if (i + k != n)
                f &= s[i + k] != 'N';

            res |= f;
        }
    }

    puts(res ? "YES" : "NO");
}

