use std::io;
use std::collections::BTreeSet;

fn max(x: &BTreeSet<i32>, y: &BTreeSet<i32>) -> (BTreeSet<i32>, BTreeSet<i32>) {
    let mut r: BTreeSet<i32> = BTreeSet::new();
    let mut rx: BTreeSet<i32> = BTreeSet::new();
    let mut xiter = x.iter();
    let mut yiter = y.iter();
    let mut i: i32 = *(xiter.next().unwrap());
    let mut j: i32 = *(yiter.next().unwrap());
    if i < j {
        while i < j { match xiter.next() {
            Some(x) => i = *x,
            None => { i = -1; break }
        } }
    } else {
        if j < i {
            while j < i { match yiter.next() {
                Some(x) => j = *x,
                None => { j = -1; break }
            } }
        }
    }
    if i != -1 { r.insert(i); }
    if j != -1 { r.insert(j); rx.insert(j); }
    for x in xiter { r.insert(*x); }
    for y in yiter { r.insert(*y); rx.insert(*y); }
    (r, rx)
}

fn main() {
    let mut l = String::new();
    io::stdin().read_line(&mut l).unwrap();
    let x: Vec<i32> = l.trim().split_whitespace().map(|x| x.parse().unwrap()).collect();
    let (_, k) = (x[0], x[1]);
    let mut xs = String::new();
    io::stdin().read_line(&mut xs).unwrap();
    let mut r: BTreeSet<i32> = BTreeSet::new();
    r.insert(-1);
    for x in xs.trim().split('Y') {
        let mut rr: BTreeSet<i32> = BTreeSet::new();
        let mut rc: BTreeSet<i32> = BTreeSet::new();
        rr.insert(-1);
        rc.insert(-1);
        for g in x.split('?') {
            let mut rs: BTreeSet<i32> = BTreeSet::new();
            let gl = g.len() as i32;
            rs.insert(gl);
            let (u, ux) = max(&rr, &rs);
            rr = &u | &(rc.iter().map(|x| x + gl + 1).collect());
            rc = &ux | &(rc.iter().map(|x| x + gl + 1).collect());
        }
        r = max(&r, &rr).0;
    }
    if r.contains(&k) {
        println!("YES");
    } else {
        println!("NO");
    }
}
